// Get the input data
const submittedAt = $input.item.json.submittedAt;
const noticePeriodDays = parseInt($input.item.json["Notice Period"]);

// Parse the submission date
const lwdDate = new Date(submittedAt);

// Add the notice period as DAYS
lwdDate.setDate(lwdDate.getDate() + noticePeriodDays);

// Helper function to pad numbers
const pad = (num) => num.toString().padStart(2, '0');

// Format to dd-mm-yyyy
const day = pad(lwdDate.getDate());
const month = pad(lwdDate.getMonth() + 1);
const year = lwdDate.getFullYear();

const lastWorkingDay = `${day}-${month}-${year}`;

return {
  lastWorkingDay
};

