// 1. GET DATA
// We assume the AI agent output is in the first item's 'output' property
let aiQuestions = items[0].json.output || [];

if (!aiQuestions.length && Array.isArray(items[0].json)) {
  aiQuestions = items.map(item => item.json); 
}

const requests = [];
let index = 0;

// ==================================================
// STEP 0: CONFIGURE FORM SETTINGS
// ==================================================
requests.push({
    updateSettings: {
        settings: {
            // REMOVED 'emailCollection' (Not supported in REST API)

            // Quiz Settings: Ensure it is NOT a quiz
            quizSettings: {
                isQuiz: false 
            }
        },
        // Mask must only contain valid fields
        updateMask: "quizSettings.isQuiz"
    }
});

// ==================================================
// STEP A: ADD HARD-CODED TOP QUESTIONS
// ==================================================

// 1. Email Address (Manual Workaround since API can't toggle the setting)
requests.push({
    createItem: {
        item: {
            title: "Email Address",
            questionItem: {
                question: {
                    required: true,
                    textQuestion: { paragraph: false }
                }
            }
        },
        location: { index: index++ } 
    }
});

// 2. Employee Name
requests.push({
    createItem: {
        item: {
            title: "Employee Name",
            questionItem: {
                question: {
                    required: true,
                    textQuestion: { paragraph: false }
                }
            }
        },
        location: { index: index++ } 
    }
});

// 3. Employee Code
requests.push({
    createItem: {
        item: {
            title: "Employee Code",
            questionItem: {
                question: {
                    required: true,
                    textQuestion: { paragraph: false }
                }
            }
        },
        location: { index: index++ } 
    }
});


// ==================================================
// STEP B: LOOP THROUGH AI QUESTIONS
// ==================================================

aiQuestions.forEach(q => {

    let questionBody = {
        required: true 
    };

    // TYPE: RATING
    if (q.question_type === 'rating') {
        questionBody.scaleQuestion = {
            low: 1,
            high: 5,
            lowLabel: "Poor",
            highLabel: "Excellent"
        };
    }

    // TYPE: LONG TEXT
    else if (q.question_type === 'long_text') {
        questionBody.textQuestion = {
            paragraph: true
        };
    }

    // TYPE: SHORT TEXT (Default)
    else {
        questionBody.textQuestion = {
            paragraph: false
        };
    }

    requests.push({
        createItem: {
            item: {
                title: q.question_text,
                questionItem: {
                    question: questionBody
                }
            },
            location: {
                index: index++ 
            }
        }
    });
});

// 3. RETURN BATCH
return {
    json: {
        requests: requests
    }
};

// 1. Fetch the filter string from your specific node
const filterString = $('Edit Fields').first().json['Employee Codes (comma-separated or array)'];

// 2. Convert that string into a clean array: ["EMP001", "EMP002", ...]
// We split by comma and trim any accidental whitespace
const allowedCodes = filterString.split(',').map(code => code.trim());

// 3. Get all the employee objects currently entering this node
const allEmployees = $input.all();

// 4. Filter the employees based on whether their code exists in our allowedCodes array
const filteredResults = allEmployees.filter(item => {
  const empCode = item.json.employee_code;
  return allowedCodes.includes(empCode);
});

return filteredResults;

